const i=n=>new Date(n).toLocaleString("zh-CN",{timeZone:"Asia/Shanghai",year:"numeric",month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit",second:"2-digit"}),r=(n,t=2)=>n==null?"--":Number(n).toFixed(t),o=n=>{if(n==null)return"--";const t=Number(n);return`${t>=0?"+":""}${t.toFixed(2)}`},s=n=>{if(n==null)return"--";const t=Number(n);return`${t>=0?"+":""}${t.toFixed(2)}%`};export{i as a,r as b,o as c,s as f};
